"use strict";parserFactory.register("novelgo.id",()=>new NovelgoParser);class NovelgoParser extends Parser{constructor(){super()}async getChapterUrls(e){let t=new URL(e.baseURI).pathname.split("/").filter(e=>""!==e),r="https://novelgo.id/wp-json/noveils/v1/chapters?paged=1&perpage=10000&category="+t[t.length-1];return(await HttpClient.fetchJson(r)).json.map(this.jsonToChapter)}jsonToChapter(e){let t=e.post_title,r=t.indexOf("Chapter");return 0<r&&(t=t.substring(r)),{sourceUrl:e.permalink,title:t.replace("&#8211","-"),newArc:null}}findContent(e){return e.querySelector("div#chapter-post-content")}extractTitleImpl(e){return e.querySelector(".novel-title")}removeUnwantedElementsFromContentElement(e){util.removeChildElementsMatchingSelector(e,"ins, div.code-block-label, .code-block"),super.removeUnwantedElementsFromContentElement(e)}findChapterTitle(e){return e.querySelector("#chapter-post-title")}findCoverImageUrl(e){let t=e.querySelector("div.novel-thumbnail");return util.extractUrlFromBackgroundImage(t)}getInformationEpubItemChildNodes(e){return[...e.querySelectorAll("div#noveils-about-tab .line-height-30 p")]}}